#[php_impl]
impl HeuristicsConfig {
    #[php(name = "from_json")]
    pub fn from_json(json: String) -> PhpResult<Self> {
        serde_json::from_str(&json).map_err(|e| PhpException::default(e.to_string()))
    }

    #[php(constructor)]
    pub fn new(
        enablePdfTextHeuristics: bool,
        textLayerThreshold: f32,
        fileSizeThresholdBytes: i64,
        pageCountThreshold: u32,
        targetPagesPerChunk: u32,
        maxPagesPerChunk: u32,
        diskProcessingThresholdBytes: i64,
        minCharsPerPage: u32,
        maxXlsxSheetCount: u32,
        maxXlsxWorkbookCells: i64,
        maxPptxEmbeddedCount: u32,
    ) -> Self {
        Self {
            enable_pdf_text_heuristics: enablePdfTextHeuristics,
            text_layer_threshold: textLayerThreshold,
            file_size_threshold_bytes: fileSizeThresholdBytes,
            page_count_threshold: pageCountThreshold,
            target_pages_per_chunk: targetPagesPerChunk,
            max_pages_per_chunk: maxPagesPerChunk,
            disk_processing_threshold_bytes: diskProcessingThresholdBytes,
            min_chars_per_page: minCharsPerPage,
            max_xlsx_sheet_count: maxXlsxSheetCount,
            max_xlsx_workbook_cells: maxXlsxWorkbookCells,
            max_pptx_embedded_count: maxPptxEmbeddedCount,
        }
    }

    pub fn get_enable_pdf_text_heuristics(&self) -> bool {
        self.enable_pdf_text_heuristics.clone()
    }

    pub fn get_text_layer_threshold(&self) -> f32 {
        self.text_layer_threshold.clone()
    }

    pub fn get_file_size_threshold_bytes(&self) -> i64 {
        self.file_size_threshold_bytes.clone()
    }

    pub fn get_page_count_threshold(&self) -> u32 {
        self.page_count_threshold.clone()
    }

    pub fn get_target_pages_per_chunk(&self) -> u32 {
        self.target_pages_per_chunk.clone()
    }

    pub fn get_max_pages_per_chunk(&self) -> u32 {
        self.max_pages_per_chunk.clone()
    }

    pub fn get_disk_processing_threshold_bytes(&self) -> i64 {
        self.disk_processing_threshold_bytes.clone()
    }

    pub fn get_min_chars_per_page(&self) -> u32 {
        self.min_chars_per_page.clone()
    }

    pub fn get_max_xlsx_sheet_count(&self) -> u32 {
        self.max_xlsx_sheet_count.clone()
    }

    pub fn get_max_xlsx_workbook_cells(&self) -> i64 {
        self.max_xlsx_workbook_cells.clone()
    }

    pub fn get_max_pptx_embedded_count(&self) -> u32 {
        self.max_pptx_embedded_count.clone()
    }

    pub fn validate(&self) -> PhpResult<()> {
        #[allow(clippy::needless_update)]
        let core_self = xberg::HeuristicsConfig {
            enable_pdf_text_heuristics: self.enable_pdf_text_heuristics,
            text_layer_threshold: self.text_layer_threshold,
            file_size_threshold_bytes: self.file_size_threshold_bytes as u64,
            page_count_threshold: self.page_count_threshold,
            target_pages_per_chunk: self.target_pages_per_chunk,
            max_pages_per_chunk: self.max_pages_per_chunk,
            disk_processing_threshold_bytes: self.disk_processing_threshold_bytes as u64,
            min_chars_per_page: self.min_chars_per_page,
            max_xlsx_sheet_count: self.max_xlsx_sheet_count,
            max_xlsx_workbook_cells: self.max_xlsx_workbook_cells as u64,
            max_pptx_embedded_count: self.max_pptx_embedded_count,
            ..Default::default()
        };
        let result = core_self
            .validate()
            .map_err(|e| ext_php_rs::exception::PhpException::default(e.to_string()))?;
        Ok(result)
    }

    #[allow(clippy::should_implement_trait)]
    #[php(name = "default")]
    pub fn default() -> HeuristicsConfig {
        xberg::HeuristicsConfig::default().into()
    }
}

