    #[cfg(any(feature = "markdown-footnotes", not(feature = "markdown-footnotes")))]
    /// Find unmarked claims in markdown text.
    ///
    /// Returns lines that assert a claim but carry neither a footnote citation anchor (`[^...]`)
    /// nor an inference marker (`[*inference*]`).
    ///
    /// The heuristic is simple: a line that contains alphabetic words, ends with sentence punctuation,
    /// and is not a heading, blank line, or markup-only line is considered a claim.
    /// Exclude lines that appear in the citation block (after `---` + `<!-- citations ... -->`).
    ///
    /// # Arguments
    ///
    /// * `markdown` - The markdown text to search
    ///
    /// # Returns
    ///
    /// A vector of trimmed line text strings for unmarked claims.
    ///
    /// # Examples
    ///
    /// ```rust
    /// let text = r#"This is a claim without citation.
    /// Another claim with citation.[^1]
    /// This is a claim with inference.[*inference*]
    ///
    /// [^1]: Citation"#;
    /// let unmarked = find_unmarked_claims(text);
    /// assert_eq!(unmarked.len(), 1);
    /// assert!(unmarked[0].contains("without citation"));
    /// ```
    #[php(name = "findUnmarkedClaims")]
    pub fn find_unmarked_claims(markdown: String) -> Vec<String> {
        xberg::find_unmarked_claims(&markdown)
    }

    #[cfg(any(feature = "markdown-footnotes", not(feature = "markdown-footnotes")))]
    /// Verify that an excerpt appears verbatim in source text.
    ///
    /// Performs exact matching by default. Also tries whitespace-normalized matching
    /// (collapsing runs of whitespace on both sides) since PDF-extracted text often
    /// has irregular spacing.
    ///
    /// # Arguments
    ///
    /// * `excerpt` - The text snippet to find
    /// * `source_text` - The full source text to search
    ///
    /// # Returns
    ///
    /// `true` if the excerpt appears (exactly or with normalized whitespace), `false` otherwise.
    ///
    /// # Examples
    ///
    /// ```rust
    /// let source = "The document states: Exact quoted text.";
    /// let excerpt = "Exact quoted text";
    /// assert!(verify_excerpt(excerpt, source));
    ///
    /// // Whitespace normalization
    /// let source2 = "Text with  irregular   spacing.";
    /// let excerpt2 = "Text with irregular spacing";
    /// assert!(verify_excerpt(excerpt2, source2));
    /// ```
    #[php(name = "verifyExcerpt")]
    pub fn verify_excerpt(excerpt: String, sourceText: String) -> bool {
        xberg::verify_excerpt(&excerpt, &sourceText)
    }

    #[cfg(any(
        any(
            any(feature = "late-interaction-presets", feature = "late-interaction"),
            feature = "late-interaction-presets"
        ),
        not(any(
            any(feature = "late-interaction-presets", feature = "late-interaction"),
            feature = "late-interaction-presets"
        ))
    ))]
    /// Score a query against a document using ColBERT's MaxSim operator: for each
    /// query token vector, take the maximum dot product against any document
    /// token vector, then sum across query tokens.
    ///
    /// Returns `0.0` if `query` and `doc` have mismatched dimensionality, if either
    /// has zero tokens, or if either is not well-formed per
    /// `MultiVectorEmbedding::is_well_formed` (its `data` length does not match
    /// `num_tokens * dim`).
    ///
    /// Pure CPU primitive — available without ONNX Runtime.
    ///
    /// Since v5.0.0.
    #[php(name = "maxSimScore")]
    pub fn max_sim_score(query: &MultiVectorEmbedding, doc: &MultiVectorEmbedding) -> f64 {
        let query_core: xberg::MultiVectorEmbedding = query.clone().into();
        let doc_core: xberg::MultiVectorEmbedding = doc.clone().into();
        xberg::max_sim_score(&query_core, &doc_core)
    }

    #[cfg(any(
        any(
            any(feature = "late-interaction-presets", feature = "late-interaction"),
            feature = "late-interaction-presets"
        ),
        not(any(
            any(feature = "late-interaction-presets", feature = "late-interaction"),
            feature = "late-interaction-presets"
        ))
    ))]
    /// Rank a set of documents against a query by MaxSim score, descending.
    ///
    /// Mirrors the sort/truncate shape of `crate::reranking`'s `build_results`,
    /// minus top-k truncation (callers slice the returned `Vec` themselves).
    ///
    /// Pure CPU primitive — available without ONNX Runtime.
    ///
    /// Since v5.0.0.
    #[php(name = "maxSimRank")]
    pub fn max_sim_rank(
        query: &MultiVectorEmbedding,
        docs: &ext_php_rs::types::ZendHashTable,
    ) -> PhpResult<Vec<LateInteractionMatch>> {
        let query_core: xberg::MultiVectorEmbedding = query.clone().into();
        let mut docs_core_result: Vec<xberg::MultiVectorEmbedding> = Vec::new();
        for (_, item) in docs.iter() {
            if let Some(parsed) = <&MultiVectorEmbedding as ext_php_rs::convert::FromZval>::from_zval(item) {
                docs_core_result.push(parsed.clone().into());
            } else {
                return Err(ext_php_rs::exception::PhpException::default(
                    "Failed to convert array element to MultiVectorEmbedding".to_string(),
                ));
            }
        }
        let docs_core: Vec<xberg::MultiVectorEmbedding> = docs_core_result;
        Ok(xberg::max_sim_rank(&query_core, &docs_core[..])
            .into_iter()
            .map(Into::into)
            .collect())
    }

