#[php_function]
pub fn register_ocr_backend(backend: &mut ext_php_rs::types::ZendObject) -> ext_php_rs::prelude::PhpResult<()> {
    let wrapper = PhpOcrBackendBridge::new(backend);
    let arc: std::sync::Arc<dyn xberg::OcrBackend> = std::sync::Arc::new(wrapper);

    let registry = xberg::plugins::registry::get_ocr_backend_registry();
    let mut registry = registry.write();
    registry
        .register(arc)
        .map_err(|e| ext_php_rs::exception::PhpException::default(format!("Failed to register backend: {}", e)))?;
    Ok(())
}

#[php_function]
pub fn unregister_ocr_backend(name: String) -> ext_php_rs::prelude::PhpResult<()> {
    xberg::plugins::ocr_backend::unregister_ocr_backend(&name)
        .map_err(|e| ext_php_rs::exception::PhpException::default(format!("{}", e)))
}

#[php_function]
pub fn clear_ocr_backends() -> ext_php_rs::prelude::PhpResult<()> {
    xberg::plugins::ocr_backend::clear_ocr_backends()
        .map_err(|e| ext_php_rs::exception::PhpException::default(format!("{}", e)))
}

/// Wrapper that bridges a foreign Php object to the `PostProcessor` trait.
pub struct PhpPostProcessorBridge {
    inner: *mut ext_php_rs::types::ZendObject,
    cached_name: String,
}

impl std::fmt::Debug for PhpPostProcessorBridge {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "PhpPostProcessorBridge")
    }
}

impl PhpPostProcessorBridge {
    /// Create a new bridge wrapping a PHP object.
    ///
    /// Validates that the PHP object provides all required methods.
    pub fn new(php_obj: &mut ext_php_rs::types::ZendObject) -> Self {
        // Validation of required methods is done in the registration function below.
        // Skipping debug_assert in constructor to avoid type issues with get_property.

        // Increment refcount to keep the object alive while registered.
        php_obj.inc_count();

        // Extract and cache name
        let cached_name = php_obj
            .try_call_method("name", vec![])
            .ok()
            .and_then(|v| v.string())
            .unwrap_or("unknown".into())
            .to_string();

        Self {
            inner: php_obj as *mut _,
            cached_name,
        }
    }
}

// SAFETY: PHP is single-threaded within a request context.
// The raw pointer to ZendObject is managed with inc_count/dec_count pairs.
unsafe impl Send for PhpPostProcessorBridge {}
unsafe impl Sync for PhpPostProcessorBridge {}

impl Drop for PhpPostProcessorBridge {
    fn drop(&mut self) {
        // SAFETY: Decrement refcount when the bridge is dropped.
        // The object pointer is guaranteed valid until this point.
        unsafe {
            if !self.inner.is_null() {
                (*self.inner).dec_count();
            }
        }
    }
}

impl xberg::plugins::Plugin for PhpPostProcessorBridge {
    fn name(&self) -> &str {
        &self.cached_name
    }

    fn version(&self) -> String {
        // SAFETY: PHP objects are single-threaded; method calls are safe within a request.
        let result = unsafe { (*self.inner).try_call_method("version", vec![]) };
        match result {
            Ok(val) => match val.string() {
                Some(json_str) => match serde_json::from_str(&json_str) {
                    Ok(v) => v,
                    Err(e) => {
                        eprintln!(
                            "[PhpPostProcessorBridge] host 'version' returned an unparseable value; returning default: {e}"
                        );
                        Default::default()
                    }
                },
                None => {
                    eprintln!("[PhpPostProcessorBridge] host 'version' returned a non-string value; returning default");
                    Default::default()
                }
            },
            // This method's Rust signature is infallible, so a PHP exception cannot
            // propagate. Log before substituting the default — a silent default is
            // indistinguishable from a real result to the caller.
            Err(e) => {
                eprintln!("[PhpPostProcessorBridge] host 'version' threw; returning default: {e}");
                Default::default()
            }
        }
    }

    fn initialize(&self) -> std::result::Result<(), xberg::XbergError> {
        if !({
            // SAFETY: PHP objects are single-threaded; reads are safe within a request.
            let __class = unsafe { (*self.inner).get_class_name().unwrap_or_default() };
            ext_php_rs::zend::Function::try_from_method(&__class, "initialize").is_some()
        }) {
            return Ok(());
        }
        // SAFETY: PHP objects are single-threaded; method calls are safe within a request.
        let result = unsafe { (*self.inner).try_call_method("initialize", vec![]) };
        match result {
            Ok(_) => Ok(()),
            Err(e) => Err(xberg::XbergError::Other(e.to_string())),
        }
    }

    fn shutdown(&self) -> std::result::Result<(), xberg::XbergError> {
        if !({
            // SAFETY: PHP objects are single-threaded; reads are safe within a request.
            let __class = unsafe { (*self.inner).get_class_name().unwrap_or_default() };
            ext_php_rs::zend::Function::try_from_method(&__class, "shutdown").is_some()
        }) {
            return Ok(());
        }
        // SAFETY: PHP objects are single-threaded; method calls are safe within a request.
        let result = unsafe { (*self.inner).try_call_method("shutdown", vec![]) };
        match result {
            Ok(_) => Ok(()),
            Err(e) => Err(xberg::XbergError::Other(e.to_string())),
        }
    }
}

