#[async_trait::async_trait]
impl xberg::RerankerBackend for PhpRerankerBackendBridge {
    async fn rerank(&self, query: String, documents: Vec<String>) -> std::result::Result<Vec<f32>, xberg::XbergError> {
        let inner_obj = self.inner;
        let cached_name = self.cached_name.clone();
        let query = query.to_string();

        // SAFETY: PHP objects are single-threaded within a request.
        // Use block_in_place if already in a tokio context; otherwise use block_on.
        if let Ok(handle) = tokio::runtime::Handle::try_current() {
            tokio::task::block_in_place(|| {
                handle.block_on(async {
                    match unsafe {
                        (*inner_obj).try_call_method(
                            "rerank",
                            [
                                ext_php_rs::types::Zval::try_from(query).unwrap_or_default(),
                                ext_php_rs::types::Zval::try_from(format!("{:?}", documents)).unwrap_or_default(),
                            ]
                            .iter()
                            .map(|z| z as &dyn ext_php_rs::convert::IntoZvalDyn)
                            .collect(),
                        )
                    } {
                        Ok(val) => {
                            let json_str = val.string().unwrap_or_default();
                            serde_json::from_str(&json_str)
                                .map_err(|e| xberg::XbergError::Other(format!("Deserialize error: {}", e)))
                        }
                        Err(e) => Err(xberg::XbergError::Other(format!(
                            "Plugin '{}' method 'rerank' failed: {}",
                            cached_name, e
                        ))),
                    }
                })
            })
        } else {
            WORKER_RUNTIME.block_on(async {
                match unsafe {
                    (*inner_obj).try_call_method(
                        "rerank",
                        [
                            ext_php_rs::types::Zval::try_from(query).unwrap_or_default(),
                            ext_php_rs::types::Zval::try_from(format!("{:?}", documents)).unwrap_or_default(),
                        ]
                        .iter()
                        .map(|z| z as &dyn ext_php_rs::convert::IntoZvalDyn)
                        .collect(),
                    )
                } {
                    Ok(val) => {
                        let json_str = val.string().unwrap_or_default();
                        serde_json::from_str(&json_str)
                            .map_err(|e| xberg::XbergError::Other(format!("Deserialize error: {}", e)))
                    }
                    Err(e) => Err(xberg::XbergError::Other(format!(
                        "Plugin '{}' method 'rerank' failed: {}",
                        cached_name, e
                    ))),
                }
            })
        }
    }
}

